using System;

Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {nints.Length}, element size: {sizeof(nint)} bytes");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  nints[{i}] = {nints[i]}");

Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 100;
nuints[1] = 200;
nuints[2] = nuint.MaxValue;

Console.WriteLine($"\nSpan<nuint> length: {nuints.Length}");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  nuints[{i}] = {nuints[i]}");

